    "id": "69ea4f7a6be32fced492fbc8",
    "name": "Necromancer",
    "description": "Necromancers manipulate the dead. Feared and hated by most people, and often justifiably so.",
    "role": "Specialist/Striker",
    "tier": "2",
    "difficulty": "3",
    "requirements": "Any class mastered.",
